from __future__ import annotations

from typing import TYPE_CHECKING

from django.shortcuts import render

if TYPE_CHECKING:
    from django.http import HttpRequest, HttpResponse


def index(request: HttpRequest) -> HttpResponse:
    return render(request, "chat/index.html")

(function () {
  const messagesEl = document.getElementById('messages');
  const formEl = document.getElementById('chat-form');
  const inputEl = document.getElementById('message-input');

  const wsScheme = window.location.protocol === 'https:' ? 'wss' : 'ws';
  const wsUrl = `${wsScheme}://${window.location.host}/ws/chat/`;
  const socket = new WebSocket(wsUrl);

  let currentAssistantEl = null;

  function appendMessage(content, sender) {
    const wrapper = document.createElement('div');
    wrapper.className = 'flex' + (sender === 'user' ? ' justify-end' : ' justify-start');

    const bubble = document.createElement('div');
    bubble.className =
      'max-w-[80%] rounded-lg px-4 py-2 whitespace-pre-wrap' +
      (sender === 'user'
        ? ' bg-blue-600 text-white'
        : ' bg-gray-800 text-gray-100 border border-gray-600');
    bubble.textContent = content;

    wrapper.appendChild(bubble);
    messagesEl.appendChild(wrapper);
    messagesEl.scrollTop = messagesEl.scrollHeight;
    return bubble;
  }

  socket.addEventListener('open', () => {
    console.log('WebSocket connected');
  });

  socket.addEventListener('message', (event) => {
    const data = JSON.parse(event.data);

    if (data.type === 'user') {
      appendMessage(data.content, 'user');
    } else if (data.type === 'assistant_start') {
      currentAssistantEl = appendMessage('', 'assistant');
    } else if (data.type === 'assistant_token') {
      if (currentAssistantEl) {
        currentAssistantEl.textContent += data.token;
        messagesEl.scrollTop = messagesEl.scrollHeight;
      }
    } else if (data.type === 'assistant_end') {
      currentAssistantEl = null;
    } else if (data.type === 'error') {
      appendMessage('Error: ' + data.message, 'assistant');
      currentAssistantEl = null;
    }
  });

  formEl.addEventListener('submit', (ev) => {
    ev.preventDefault();
    const text = inputEl.value.trim();
    if (!text || socket.readyState !== WebSocket.OPEN) return;
    socket.send(JSON.stringify({ message: text }));
    inputEl.value = '';
  });
})();

